 1 /**
 2  * Todo list focus management -- progressive enhancement for HTMX.
 3  *
 4  * After an HTMX delete swap removes a todo item from the DOM, focus
 5  * would otherwise be lost (sent to <body>). This script moves focus
 6  * to the logical next element:
 7  *
 8  * 1. Next sibling todo item (if one exists)
 9  * 2. Previous sibling todo item (if deleted was last in list)
10  * 3. The "New todo" input (if the list is now empty)
11  *
12  * A11y: Focus management after DOM removal is required by WCAG 2.4.3
13  * (Focus Order) and is part of our HTMX Focus Management Protocol.
14  */
15 (function () {
16   "use strict";
17 
18   // Track the focus target before the swap removes the element
19   var pendingFocusTarget = null;
20 
21   document.body.addEventListener("htmx:beforeSwap", function (e) {
22     var target = e.detail.target;
23 
24     // Only handle delete swaps (empty response that removes an element)
25     if (!target || !target.classList || !target.classList.contains("todo-item")) {
26       return;
27     }
28 
29     // If the response body is empty, this is a delete operation
30     var responseText = e.detail.xhr ? e.detail.xhr.responseText : "";
31     if (responseText.trim() !== "") {
32       return;
33     }
34 
35     // Determine focus target before the element is removed
36     var nextItem = target.nextElementSibling;
37     var prevItem = target.previousElementSibling;
38 
39     if (nextItem && nextItem.classList.contains("todo-item")) {
40       pendingFocusTarget = nextItem;
41     } else if (prevItem && prevItem.classList.contains("todo-item")) {
42       pendingFocusTarget = prevItem;
43     } else {
44       // List will be empty after this deletion -- focus the add input
45       pendingFocusTarget = document.getElementById("title");
46     }
47   });
48 
49   document.body.addEventListener("htmx:afterSettle", function () {
50     if (!pendingFocusTarget) {
51       return;
52     }
53 
54     var el = pendingFocusTarget;
55     pendingFocusTarget = null;
56 
57     // Make the target focusable if it isn't already
58     if (!el.hasAttribute("tabindex") && el.tagName !== "INPUT" && el.tagName !== "BUTTON" && el.tagName !== "A") {
59       el.setAttribute("tabindex", "-1");
60     }
61 
62     el.focus();
63   });
64 })();
65 

